INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c5cb5266-2db7-43d1-a71d-870bc3f65055',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep vs Terraform: Providers, State & Plan/Apply — What Bicep Does Differently$escape$,
  $escape$Terraform's provider/state/plan-apply model has direct analogues in Bicep, but the mechanics differ significantly. In Bicep, providers aren't declared separately — they're embedded in the resource type string itself (e.g., `Microsoft.Network/virtualNetworks@2023-04-01`). The `@apiVersion` suffix pins the provider contract, equivalent to locking a Terraform provider version in `required_providers`.

State is the biggest conceptual shift. Bicep has no local `.tfstate` file. Azure Resource Manager owns the truth — every deployment is a declarative diff against ARM's server-side state. This eliminates state drift and backend locking nightmares, but you lose Terraform's fine-grained `import` and `state mv` primitives.

The plan/apply lifecycle maps cleanly: `az deployment group what-if` surfaces a change preview (create, modify, delete, no-change) before you commit. `az deployment group create` applies it. The `--confirm-with-what-if` flag fuses both steps into a single interactive command. `--mode Complete` is the nuclear option — resources absent from the template are deleted, matching Terraform's full `destroy`-then-`apply` sweep.$escape$,
  $escape$// vnet.bicep — provider namespace embedded in type string
resource vnet 'Microsoft.Network/virtualNetworks@2023-04-01' = {
  name: 'my-vnet'
  location: resourceGroup().location
  properties: {
    addressSpace: { addressPrefixes: ['10.0.0.0/16'] }
  }
}

# What-if (terraform plan equivalent)
az deployment group what-if \
  --resource-group my-rg \
  --template-file vnet.bicep

# Apply (terraform apply equivalent)
az deployment group create \
  --resource-group my-rg \
  --template-file vnet.bicep \
  --mode Incremental$escape$,
