INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e81cdbbf-0a0d-419e-bb92-0ab374f60fda',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Modules — Registry Publishing and Versioning Strategy$escape$,
  $escape$Bicep modules let you encapsulate resource definitions into reusable units, but the real power kicks in when you publish them to a private Azure Container Registry (ACR). Use `az bicep publish` to push a module to your registry under a semantic version tag. Consumers reference it via the `br:` scheme with a pinned version — never a mutable `latest` tag in production.

Version your modules with `major.minor.patch` semantics: bump major for breaking parameter changes, minor for new optional parameters, patch for bug fixes or metadata tweaks. Store the module source in a `modules/` directory at the repo root and gate publish to the registry behind a CI step that enforces version bumps before merge.

For team-wide adoption, set a `bicepconfig.json` at the repo root with a `moduleAliases` block — this lets consumers write `br/shared:storage/v2` instead of the full ACR URL, making module references refactor-safe if you ever migrate registries.$escape$,
  $escape$// bicepconfig.json — alias your private registry
{
  "moduleAliases": {
    "br": {
      "shared": {
        "registry": "myacr.azurecr.io",
        "modulePath": "bicep/modules"
      }
    }
  }
}

// main.bicep — consume a pinned module version
module storage 'br/shared:storage:2.1.0' = {
  name: 'storageDeployment'
  params: {
    storageAccountName: 'mystorageacct'
    sku: 'Standard_LRS'
  }
}$escape$,
  $escape$bash$escape$,
