INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'efbf50d9-125f-4550-aadb-73c8403df9ef',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Secrets — Keep Them Out of ARM Deployment History$escape$,
  $escape$Every value you pass as a plain `string` parameter in Bicep lands in Azure's ARM deployment history — readable by anyone with `Microsoft.Resources/deployments/read`. For secrets, use the `@secure()` decorator: ARM redacts those values from history and logs. But the real pattern is never accepting the secret in Bicep at all. Reference Key Vault directly via a `getSecret()` call on the Key Vault `existing` resource — the secret is resolved server-side during deployment and never touches your parameter file or deployment history. Pair this with a `Microsoft.KeyVault/vaults` `existing` reference scoped to the correct resource group. For dynamic secrets like connection strings generated post-deploy (e.g. a storage account key), use a `listKeys()` call and pipe it straight into the consuming resource's `properties` block — again, never materializing the value as a named output. Mark any output that must carry a secret with `@secure()` too, or ARM will log it. The combination of `@secure()` + Key Vault references + avoiding secret outputs is the full defense.$escape$,
  $escape$param keyVaultName string
param secretName string

resource kv 'Microsoft.KeyVault/vaults@2023-07-01' existing = {
  name: keyVaultName
}

resource appService 'Microsoft.Web/sites@2023-01-01' = {
  name: 'my-app'
  location: resourceGroup().location
  properties: {
    siteConfig: {
      appSettings: [
        {
          name: 'DB_PASSWORD'
          value: kv.getSecret(secretName)
        }
      ]
    }
  }
}$escape$,
  $escape$bash$escape$,
