INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36e30e16-513e-468d-86bb-9b8127644f63',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep existing Keyword — Importing Real Infra Into Your IaC$escape$,
  $escape$Bicep separates two distinct intents when dealing with pre-existing Azure resources. The `existing` keyword lets you reference a resource Bicep doesn't own — pulling its properties and resource ID without touching its lifecycle. This is ideal for cross-RG dependencies like a shared Key Vault or VNet. To actually bring a resource under Bicep management, define it normally and redeploy — ARM is idempotent and adopts matching resources in-place rather than recreating them. The safest workflow: export the resource as ARM JSON via the Azure Portal, run `az bicep decompile --file exported.json` to get a `.bicep` scaffold, reconcile drift against live config, then deploy with `az deployment group create --what-if` first. Watch for properties ARM silently sets (like `defaultAction` on storage firewall rules) that will show as diffs on first what-if but won't cause downtime. Once deployed, the resource is owned by your Bicep module — subsequent changes flow through code. Never mix `existing` references and full resource declarations for the same resource in one template; ARM will conflict on the resource ID.$escape$,
  $escape$// Read-only reference — Bicep does NOT manage this resource
resource sharedKv 'Microsoft.KeyVault/vaults@2023-07-01' existing = {
  name: 'prod-shared-kv'
  scope: resourceGroup('shared-infra-rg')
}

// Bring existing storage account under management (idempotent adoption)
resource storage 'Microsoft.Storage/storageAccounts@2023-01-01' = {
  name: 'mylegacystorage'
  location: resourceGroup().location
  sku: { name: 'Standard_LRS' }
  kind: 'StorageV2'
  properties: { minimumTlsVersion: 'TLS1_2' }
}

// Safe first-deploy check
// az deployment group create --what-if -g my-rg -f main.bicep$escape$,
  $escape$bash$escape$,
