INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '95745840-5120-48e2-a490-9a05c7d9a1f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Cost Estimation — Shift Left with Infracost Before az deployment create$escape$,
  $escape$Infracost doesn't natively parse `.bicep` files — it consumes ARM JSON. The workflow is: compile first, estimate second. Run `az bicep build --file main.bicep --outfile main.arm.json`, then point Infracost at the output. Infracost reads resource types and SKUs from the ARM template's `resources` array, maps them to Azure Pricing API entries, and surfaces a cost breakdown before any `az deployment group create` ever runs.

In CI, wire this into your PR pipeline: compile the Bicep, run `infracost diff --path main.arm.json --compare-to base.arm.json`, and post the delta as a PR comment. A `Microsoft.Compute/virtualMachines` switching from `Standard_B2s` to `Standard_D4s_v3` will surface a ~4× monthly cost increase before merge.

Watch for resources Infracost can't price — `Microsoft.Resources/deploymentScripts` and custom roleAssignments show as `$0`. Treat those as manual estimation items. For modules using `existing` keyword references, costs won't appear — only net-new resources declared with `resource` blocks are evaluated.$escape$,
  $escape$# 1. Compile Bicep to ARM JSON
az bicep build --file infra/main.bicep --outfile infra/main.arm.json

# 2. Estimate costs before deployment
infracost breakdown --path infra/main.arm.json

# 3. In CI: diff against base branch ARM output
infracost diff \
  --path infra/main.arm.json \
  --compare-to infra/base.arm.json \
  --format json \
  --out-file infracost-diff.json

# 4. Post to PR (GitHub Actions)
infracost comment github \
  --path infracost-diff.json \
  --repo $GITHUB_REPOSITORY \
  --pull-request $PR_NUMBER \
  --github-token $GITHUB_TOKEN$escape$,
  $escape$bash$escape$,
