INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '94271579-a28d-423e-9568-1cb85062d2f9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bicep Linting & Formatting — Enforcing Consistent Style with bicepconfig.json$escape$,
  $escape$Bicep ships a built-in linter — no tflint needed. Rules are controlled via `bicepconfig.json` at the repo root, which Bicep CLI picks up automatically during `bicep build` and in the VS Code extension. Each rule has a `level` of `off`, `warning`, or `error`. Elevate `no-unused-params`, `no-unused-vars`, and `secure-secrets-in-params` to `error` in CI to block merges on common hygiene issues. The `prefer-interpolation` rule catches string concatenation that should use `'${var}'` syntax. For formatting, `bicep format main.bicep` (CLI v0.14+) rewrites indentation, spacing, and newlines in place — pipe it into a pre-commit hook or a GitHub Actions step with `bicep format --check` to fail on unformatted files without mutating them. Combining linter-as-error with format-check in CI means style drift never reaches main. Run `az bicep upgrade` to keep the linter rule set current; Microsoft adds new rules with each release.$escape$,
  $escape$// bicepconfig.json
{
  "analyzers": {
    "core": {
      "enabled": true,
      "rules": {
        "no-unused-params": { "level": "error" },
        "no-unused-vars": { "level": "error" },
        "secure-secrets-in-params": { "level": "error" },
        "prefer-interpolation": { "level": "warning" },
        "use-stable-vm-image": { "level": "warning" },
        "no-hardcoded-env-urls": { "level": "error" }
      }
    }
  }
}$escape$,
  $escape$bash$escape$,
